CREATE VIEW IF NOT EXISTS v_pls_channel_dimension_features AS
SELECT
  workspace_id,
  canonical_object_key,
  object_type,
  display_name,
  platform_name,
  platform_type,
  layer_code,
  layer_name,
  dimension_code,
  dimension_name,
  dimension_definition,
  business_strategy,
  COUNT(*) AS tag_count,
  ROUND(SUM(tag_score), 6) AS dimension_score,
  ROUND(AVG(tag_score), 6) AS avg_tag_score,
  ROUND(MAX(tag_score), 6) AS max_tag_score,
  ROUND(AVG(tag_confidence), 6) AS avg_tag_confidence,
  ROUND(AVG(mapping_confidence), 6) AS avg_mapping_confidence,
  GROUP_CONCAT(DISTINCT tag_id) AS tag_ids,
  GROUP_CONCAT(DISTINCT tag_label_zh) AS tag_labels_zh,
  MIN(time_window) AS first_time_window,
  MAX(time_window) AS last_time_window,
  MIN(generated_at) AS first_generated_at,
  MAX(generated_at) AS last_generated_at,
  MAX(profile_updated_at) AS latest_profile_updated_at,
  MAX(mapping_updated_at) AS latest_mapping_updated_at
FROM v_pls_audience_tag_semantics
GROUP BY
  workspace_id,
  canonical_object_key,
  object_type,
  display_name,
  platform_name,
  platform_type,
  layer_code,
  layer_name,
  dimension_code,
  dimension_name,
  dimension_definition,
  business_strategy;

INSERT OR IGNORE INTO database_field_comments (
  id,
  table_name,
  field_name,
  zh_name,
  zh_description,
  business_meaning,
  example_value,
  source_ref,
  status,
  created_at,
  updated_at
)
